import { createSlice, createAsyncThunk } from '@reduxjs/toolkit';
import axios from 'axios';

// Async thunks for restaurants
export const fetchRestaurants = createAsyncThunk(
  'restaurants/fetchRestaurants',
  async ({ location, cuisine, search }, { rejectWithValue }) => {
    try {
      const params = new URLSearchParams();
      if (location) params.append('location', location);
      if (cuisine) params.append('cuisine', cuisine);
      if (search) params.append('search', search);

      const response = await axios.get(`/api/restaurants?${params}`);
      return response.data;
    } catch (error) {
      return rejectWithValue(error.response.data.message);
    }
  }
);

export const fetchRestaurantById = createAsyncThunk(
  'restaurants/fetchRestaurantById',
  async (restaurantId, { rejectWithValue }) => {
    try {
      const response = await axios.get(`/api/restaurants/${restaurantId}`);
      return response.data;
    } catch (error) {
      return rejectWithValue(error.response.data.message);
    }
  }
);

export const fetchMenu = createAsyncThunk(
  'restaurants/fetchMenu',
  async (restaurantId, { rejectWithValue }) => {
    try {
      const response = await axios.get(`/api/restaurants/${restaurantId}/menu`);
      return response.data;
    } catch (error) {
      return rejectWithValue(error.response.data.message);
    }
  }
);

export const fetchCuisines = createAsyncThunk(
  'restaurants/fetchCuisines',
  async (_, { rejectWithValue }) => {
    try {
      const response = await axios.get('/api/cuisines');
      return response.data;
    } catch (error) {
      return rejectWithValue(error.response.data.message);
    }
  }
);

const initialState = {
  restaurants: [],
  currentRestaurant: null,
  menu: [],
  cuisines: [],
  loading: false,
  error: null,
  filters: {
    location: '',
    cuisine: '',
    search: '',
    priceRange: [0, 1000],
    rating: 0,
  },
};

const restaurantSlice = createSlice({
  name: 'restaurants',
  initialState,
  reducers: {
    setFilters: (state, action) => {
      state.filters = { ...state.filters, ...action.payload };
    },

    clearFilters: (state) => {
      state.filters = {
        location: '',
        cuisine: '',
        search: '',
        priceRange: [0, 1000],
        rating: 0,
      };
    },

    clearError: (state) => {
      state.error = null;
    },

    clearCurrentRestaurant: (state) => {
      state.currentRestaurant = null;
      state.menu = [];
    },
  },

  extraReducers: (builder) => {
    builder
      // Fetch Restaurants
      .addCase(fetchRestaurants.pending, (state) => {
        state.loading = true;
        state.error = null;
      })
      .addCase(fetchRestaurants.fulfilled, (state, action) => {
        state.loading = false;
        state.restaurants = action.payload.restaurants;
      })
      .addCase(fetchRestaurants.rejected, (state, action) => {
        state.loading = false;
        state.error = action.payload;
      })

      // Fetch Restaurant By ID
      .addCase(fetchRestaurantById.pending, (state) => {
        state.loading = true;
        state.error = null;
      })
      .addCase(fetchRestaurantById.fulfilled, (state, action) => {
        state.loading = false;
        state.currentRestaurant = action.payload.restaurant;
      })
      .addCase(fetchRestaurantById.rejected, (state, action) => {
        state.loading = false;
        state.error = action.payload;
      })

      // Fetch Menu
      .addCase(fetchMenu.pending, (state) => {
        state.loading = true;
        state.error = null;
      })
      .addCase(fetchMenu.fulfilled, (state, action) => {
        state.loading = false;
        state.menu = action.payload.menu;
      })
      .addCase(fetchMenu.rejected, (state, action) => {
        state.loading = false;
        state.error = action.payload;
      })

      // Fetch Cuisines
      .addCase(fetchCuisines.fulfilled, (state, action) => {
        state.cuisines = action.payload.cuisines;
      });
  },
});

export const { setFilters, clearFilters, clearError, clearCurrentRestaurant } = restaurantSlice.actions;
export default restaurantSlice.reducer;
